113→// ─── LLM-powered export types (co-located, not in cli/src/types.ts) ──────────
114→
115→interface ExportGenerateBody {
116→  scope: ExportScope;
117→  projectId?: string;
118→  format: ExportFormat;
119→  depth?: ExportDepth;
120→}
121→
122→interface ExportGenerateMetadata {
123→  insightCount: number;    // insights actually sent to LLM
124→  totalInsights: number;   // total insights available for scope
125→  sessionCount: number;
126→  projectCount: number;
127→  scope: ExportScope;
128→  depth: ExportDepth;
129→}
130→
131→// Fetch scoped insights ordered by confidence DESC, timestamp DESC.
132→// Excludes 'summary' type — per-session summaries aren't cross-session knowledge.
133→function fetchScopedInsights(
134→  db: ReturnType<typeof getDb>,
135→  scope: ExportScope,
136→  projectId: string | undefined
137→): ExportInsightRow[] {
138→  if (scope === 'project') {
139→    if (!projectId) return [];
140→    return db.prepare(`
141→      SELECT id, type, title, content, summary, confidence, project_name, timestamp
142→      FROM insights
143→      WHERE project_id = ? AND type != 'summary'
144→      ORDER BY confidence DESC, timestamp DESC
145→    `).all(projectId) as ExportInsightRow[];
146→  }
147→
148→  return db.prepare(`
149→    SELECT id, type, title, content, summary, confidence, project_name, timestamp
150→    FROM insights
151→    WHERE type != 'summary'
152→    ORDER BY confidence DESC, timestamp DESC
153→  `).all() as ExportInsightRow[];
154→}
155→
156→function fetchSessionContext(
157→  db: ReturnType<typeof getDb>,
158→  scope: ExportScope,
159→  projectId: string | undefined
160→): { sessionCount: number; projectCount: number; projectName: string | undefined; dateFrom: string; dateTo: string } {
161→  const today = new Date().toISOString().slice(0, 10);
162→
163→  if (scope === 'project' && projectId) {
164→    const row = db.prepare(`
165→      SELECT COUNT(*) as cnt, MIN(started_at) as min_date, MAX(ended_at) as max_date, project_name
166→      FROM sessions WHERE project_id = ?
167→    `).get(projectId) as { cnt: number; min_date: string; max_date: string; project_name: string } | undefined;
168→    return {
169→      sessionCount: row?.cnt ?? 0,
170→      projectCount: 1,
171→      projectName: row?.project_name,
172→      dateFrom: row?.min_date?.slice(0, 10) ?? today,
173→      dateTo: row?.max_date?.slice(0, 10) ?? today,
174→    };
175→  }
176→
177→  const row = db.prepare(`
178→    SELECT COUNT(*) as session_cnt,
179→           COUNT(DISTINCT project_id) as project_cnt,
180→           MIN(started_at) as min_date,
181→           MAX(ended_at) as max_date
182→    FROM sessions
183→  `).get() as { session_cnt: number; project_cnt: number; min_date: string; max_date: string } | undefined;
184→
185→  return {
186→    sessionCount: row?.session_cnt ?? 0,
187→    projectCount: row?.project_cnt ?? 0,
188→    projectName: undefined,
189→    dateFrom: row?.min_date?.slice(0, 10) ?? today,
190→    dateTo: row?.max_date?.slice(0, 10) ?? today,
191→  };
192→}
