194→// POST /api/export/generate
195→// Synchronous LLM export — returns full result when complete.
196→app.post('/generate', async (c) => {
197→  if (!isLLMConfigured()) {
198→    return c.json({
199→      success: false,
200→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
201→    }, 400);
202→  }
203→
204→  const body = await c.req.json<ExportGenerateBody>();
205→  const { scope, projectId, format, depth = 'standard' } = body;
206→
207→  if (scope !== 'project' && scope !== 'all') {
208→    return c.json({ error: 'scope must be "project" or "all"' }, 400);
209→  }
210→  if (scope === 'project' && !projectId) {
211→    return c.json({ error: 'projectId is required when scope is "project"' }, 400);
212→  }
213→  if (!['agent-rules', 'knowledge-brief', 'obsidian', 'notion'].includes(format)) {
214→    return c.json({ error: 'format must be one of: agent-rules, knowledge-brief, obsidian, notion' }, 400);
215→  }
216→  if (!['essential', 'standard', 'comprehensive'].includes(depth)) {
217→    return c.json({ error: 'depth must be one of: essential, standard, comprehensive' }, 400);
218→  }
219→
220→  const db = getDb();
221→  const llmConfig = loadLLMConfig();
222→  const startTime = Date.now();
223→
224→  try {
225→    const rawInsights = fetchScopedInsights(db, scope, projectId);
226→    const { capped, totalInsights } = applyDepthCap(rawInsights, depth);
227→    const sessionCtx = fetchSessionContext(db, scope, projectId);
228→
229→    const ctx = {
230→      scope,
231→      format,
232→      depth,
233→      projectName: sessionCtx.projectName,
234→      sessionCount: sessionCtx.sessionCount,
235→      projectCount: sessionCtx.projectCount,
236→      dateRange: { from: sessionCtx.dateFrom, to: sessionCtx.dateTo },
237→      exportDate: new Date().toISOString().slice(0, 10),
238→    };
239→
240→    const systemPrompt = getExportSystemPrompt(ctx);
241→    const insightContext = buildInsightContext(capped);
242→    const userPrompt = buildExportUserPrompt(ctx, insightContext);
243→
244→    const client = createLLMClient();
245→    const response = await client.chat([
246→      { role: 'system', content: systemPrompt },
247→      { role: 'user', content: userPrompt },
248→    ], { signal: c.req.raw.signal });
249→
250→    const metadata: ExportGenerateMetadata = {
251→      insightCount: capped.length,
252→      totalInsights,
253→      sessionCount: sessionCtx.sessionCount,
254→      projectCount: sessionCtx.projectCount,
255→      scope,
256→      depth,
257→    };
258→
259→    trackEvent('export_run', {
260→      format: `llm-${format}`,
261→      scope,
262→      depth,
263→      insight_count: capped.length,
264→      session_count: sessionCtx.sessionCount,
265→      llm_provider: llmConfig?.provider,
266→      llm_model: llmConfig?.model,
267→      duration_ms: Date.now() - startTime,
268→      success: true,
269→    });
270→
271→    return c.json({ content: response.content, metadata }, 200);
272→  } catch (error) {
273→    if (error instanceof Error && error.name === 'AbortError') {
274→      // Client disconnected — 422 is the closest Hono allows; client ignores this on abort
275→      return c.json({ error: 'Export cancelled' }, 422);
276→    }
277→    const message = error instanceof Error ? error.message : 'Export generation failed';
278→    captureError(error, { format, scope, depth, llm_provider: llmConfig?.provider, llm_model: llmConfig?.model });
279→    trackEvent('export_run', {
280→      format: `llm-${format}`,
281→      scope,
282→      depth,
283→      llm_provider: llmConfig?.provider,
284→      llm_model: llmConfig?.model,
285→      duration_ms: Date.now() - startTime,
286→      success: false,
287→      error_message: message,
288→    });
289→    return c.json({ error: message }, 422);
290→  }
291→});
292→
293→// GET /api/export/generate/stream?scope=project&projectId=xxx&format=agent-rules&depth=standard
294→// SSE endpoint — streams progress events during LLM export generation.
295→// onProgress is implicit (no chunked analysis here); stream.writeSSE is fire-and-forget
296→// for progress events (non-fatal if missed).
297→app.get('/generate/stream', async (c) => {
298→  if (!isLLMConfigured()) {
299→    return c.json({
300→      success: false,
301→      error: 'LLM not configured. Run `code-insights config llm` to configure a provider.',
302→    }, 400);
303→  }
304→
305→  const scope = c.req.query('scope') as ExportScope | undefined;
306→  const projectId = c.req.query('projectId');
307→  const format = c.req.query('format') as ExportFormat | undefined;
308→  const depth = (c.req.query('depth') ?? 'standard') as ExportDepth;
309→
310→  if (scope !== 'project' && scope !== 'all') {
311→    return c.json({ error: 'scope must be "project" or "all"' }, 400);
312→  }
313→  if (scope === 'project' && !projectId) {
314→    return c.json({ error: 'projectId is required when scope is "project"' }, 400);
315→  }
316→  if (!format || !['agent-rules', 'knowledge-brief', 'obsidian', 'notion'].includes(format)) {
317→    return c.json({ error: 'format must be one of: agent-rules, knowledge-brief, obsidian, notion' }, 400);
318→  }
319→  if (!['essential', 'standard', 'comprehensive'].includes(depth)) {
320→    return c.json({ error: 'depth must be one of: essential, standard, comprehensive' }, 400);
321→  }
322→
323→  const db = getDb();
324→  const llmConfig = loadLLMConfig();
325→
326→  return streamSSE(c, async (stream) => {
327→    const streamStart = Date.now();
328→    try {
329→      const abortSignal = c.req.raw.signal;
330→
331→      // Phase 1: load and count insights, emit counts before LLM call
332→      const rawInsights = fetchScopedInsights(db, scope, projectId);
333→      const { capped, totalInsights } = applyDepthCap(rawInsights, depth);
334→
335→      await stream.writeSSE({
336→        event: 'progress',
337→        data: JSON.stringify({
338→          phase: 'loading_insights',
339→          insightCount: capped.length,
340→          totalInsights,
341→        }),
342→      });
343→
344→      if (capped.length === 0) {
345→        await stream.writeSSE({
346→          event: 'error',
347→          data: JSON.stringify({ error: 'No insights found for the selected scope. Run analysis on some sessions first.' }),
348→        });
349→        return;
350→      }
351→
352→      // Phase 2: synthesizing
353→      void stream.writeSSE({
354→        event: 'progress',
355→        data: JSON.stringify({ phase: 'synthesizing', progress: 'Sending to LLM...' }),
356→      }).catch(() => {});
357→
358→      const sessionCtx = fetchSessionContext(db, scope, projectId);
359→      const ctx = {
360→        scope,
361→        format,
362→        depth,
363→        projectName: sessionCtx.projectName,
364→        sessionCount: sessionCtx.sessionCount,
365→        projectCount: sessionCtx.projectCount,
366→        dateRange: { from: sessionCtx.dateFrom, to: sessionCtx.dateTo },
367→        exportDate: new Date().toISOString().slice(0, 10),
368→      };
369→
370→      const systemPrompt = getExportSystemPrompt(ctx);
371→      const insightContext = buildInsightContext(capped);
372→      const userPrompt = buildExportUserPrompt(ctx, insightContext);
373→
374→      const client = createLLMClient();
375→      const response = await client.chat([
376→        { role: 'system', content: systemPrompt },
377→        { role: 'user', content: userPrompt },
378→      ], { signal: abortSignal });
379→
380→      const metadata: ExportGenerateMetadata = {
381→        insightCount: capped.length,
382→        totalInsights,
383→        sessionCount: sessionCtx.sessionCount,
384→        projectCount: sessionCtx.projectCount,
385→        scope,
386→        depth,
387→      };
388→
389→      trackEvent('export_run', {
390→        format: `llm-${format}`,
391→        scope,
392→        depth,
393→        insight_count: capped.length,
394→        session_count: sessionCtx.sessionCount,
395→        llm_provider: llmConfig?.provider,
396→        llm_model: llmConfig?.model,
397→        duration_ms: Date.now() - streamStart,
398→        success: true,
399→      });
400→
401→      // Phase 3: complete — send full content + metadata
402→      await stream.writeSSE({
403→        event: 'complete',
404→        data: JSON.stringify({ content: response.content, metadata }),
405→      });
406→    } catch (err) {
407→      const message = err instanceof Error ? err.message : 'Unknown error';
408→      captureError(err, { format, scope, depth, llm_provider: llmConfig?.provider, llm_model: llmConfig?.model });
409→      trackEvent('export_run', {
410→        format: `llm-${format}`,
411→        scope,
412→        depth,
413→        llm_provider: llmConfig?.provider,
414→        llm_model: llmConfig?.model,
415→        duration_ms: Date.now() - streamStart,
416→        success: false,
417→        error_message: message,
418→      });
419→      await stream.writeSSE({
420→        event: 'error',
421→        data: JSON.stringify({ error: message }),
422→      }).catch(() => {});
423→    }
424→  });
425→});
426→
427→export default app;
